  "verses": [
    {
      "n": 18,
      "column": "left",
      "text": "Un wiꞥſch aptehrpſees ar\nto Lahſtu/ ta ka ar fawn Drehy-\nbi/ un tas ees winna Eekſchâs/\nka Uhdens / un ka Etje winna\nKaulôs."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Tas pats buhs winnam\nka Apgehrbs/ ar ko wiꞥſch ap-\nfedsahs/ un par Jobſtu/ ar ko\nwiꞥſch allach apjohſchahs."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Schi Alga lai noteek no\nta KUNGA manncem Pretti-\nneefeem / un teem / kas Taunu\nrunna prett mannu Dwebſeli."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Bet tn/ af KUNGS\nKungß! darrajs ar mannim ta-\nwa Wahrda pehz/ jo tawa\nSchehlaſtiba irr labba / iſglahb\nmannis."
    },
    {
      "n": 22,
      "column": "left",
      "text": "Jo es etmu behdigs un\nnabbags/ un manna Girds eekſch\nmannim irr eewainota."
    },
    {
      "n": 23,
      "column": "left",
      "text": "Es aiseemu/ ka Eyna/\nkas notezz/ un tohpu wajahts/\nka weens Siffenis."
    },
    {
      "n": 24,
      "column": "left",
      "text": "Manni Zetti irr wahji no\nGawefchanaß/ un manna Mee-\nfa leefa tappufi/ ka Tauku ne-\nwaid klaht."
    },
    {
      "n": 25,
      "column": "left",
      "text": "Un man buhs teem wehl\nbuht par Smeekli/ kad tee man-\nnis reds/ tad tee fawn Galwu\nkratta."
    },
    {
      "n": 26,
      "column": "left",
      "text": "Valihds man/ KUNGS\nmans Deews/ atpesti mannis\npehz tawas Schehlaſtibas."
    },
    {
      "n": 27,
      "column": "left",
      "text": "Ka tee atſihſt/ ſcho effam"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Kad tee nolahd/ tad t\nſwehti/ kad tee zelkahs (preſ\nmann/)tad lai tee tohp Kauna-\nbet taws Kalps lai preezajahs."
    },
    {
      "n": 29,
      "column": "right",
      "text": "Manni Prettineeki lai\nKaunu tohp apgehrbti/ un\nfawn Negohdu apſegti / ka\nSwahrkeem."
    },
    {
      "n": 30,
      "column": "right",
      "text": "Es pateikſchu tam KUN-\nGAM fohti ar fawnu Mutti\nun dfeedaſchn tam starp da-\ndseem."
    },
    {
      "n": 31,
      "column": "right",
      "text": "Jo wiꞥſch ſtahw ta-\nBehdigam pa labbo Rohku/ a-\npeſtidains to no teem/ kas wi-\nna Oſhwibn noteefa."
    }
  ],
  "confidence": "high",
